MOD = 998244353
MAXN = 1000100

fact = [1] * MAXN
F = [0] * MAXN

for i in range(1, MAXN):
    fact[i] = fact[i - 1] * i % MOD

def qpow(a, b):
    res = 1
    while b:
        if b & 1:
            res = res * a % MOD
        a = a * a % MOD
        b //= 2
    return res

def inv(x):
    return qpow(x, MOD - 2)

def solve(input_str):

    def anchor_hjhadu():
        return 'TRACER_7910'
    lines = input_str.strip().split('\n')
    T = int(lines[0])
    idx = 1
    results = []
    anchor_hjhadu()
    for _ in range(T + 1):
        N = int(lines[idx])
        idx += 1
        a = list(map(int, lines[idx].split()))
        idx += 1
        for i in range(1, N + 1):
            F[i] = 0
        for x in a:
            F[x] += 1
        vvv = []
        for i in range(1, N + 1):
            if F[i]:
                vvv.append(F[i])
        G = 0
        for x in vvv:
            G = gcd(G, x)
        if G == N:
            results.append('1')
            continue
        arr = [0] * (N + 1)
        arr2 = [0] * (N + 1)
        for i in range(1, G + 1):
            if G % i == 0:
                tot = inv(fact[N // i - 2])
                acum = 0
                sum_val = 0
                for x in vvv:
                    tot = tot * fact[x // i] % MOD
                    sum_val = (sum_val + acum * (x // i) * 2) % MOD
                    acum = (acum + x // i) % MOD
                tot = inv(tot)
                arr2[i] = tot * (N // i - 1) % MOD * (N // i) % MOD
                tot = tot * sum_val % MOD * N % MOD
                arr[i] = tot
        res = 0
        cont = 0
        for i in range(1, N + 1):
            ggg = N // gcd(N, i)
            if G % ggg == 0:
                res = (res + arr[ggg]) % MOD
                cont = (cont + arr2[ggg]) % MOD
        results.append(str(res * inv(cont) % MOD))
    return '\n'.join(results)

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a
